'use strict';

var valid = [];

// String concatenation in non-error constructor:
var test = {
	'code': 'new MyClass( \'prefix\' + value );'
};
valid.push( test );

// String concatenation in regular function call:
test = {
	'code': 'console.log( \'value: \' + x );'
};
valid.push( test );

// String concatenation assigned to variable, then used in error:
test = {
	'code': 'var msg = \'invalid: \' + x;\nthrow new Error( msg );'
};
valid.push( test );

// Member expression (not a simple identifier):
test = {
	'code': 'throw new errors.CustomError( \'prefix\' + value );'
};
valid.push( test );

// String concatenation in second argument:
test = {
	'code': 'throw new Error( \'message\', \'cause: \' + x );'
};
valid.push( test );


// EXPORTS //

module.exports = valid;
